import React, { useState, useEffect } from 'react';
import { db } from '../firebase/config';
import { doc, setDoc, onSnapshot } from 'firebase/firestore';

const DEFAULT_CATEGORIES = [
  { id: 'rings', label: 'Rings', image: '' },
  { id: 'necklaces', label: 'Necklaces', image: '' },
  { id: 'earrings', label: 'Earrings', image: '' },
  { id: 'bracelets', label: 'Bracelets', image: '' }
];

export default function CategoryManager() {
  const [categories, setCategories] = useState(DEFAULT_CATEGORIES);

  // 🔥 Fetch categories (real-time)
  useEffect(() => {
    const unsub = onSnapshot(doc(db, 'categories', 'main'), (docSnap) => {
      if (docSnap.exists()) {
        setCategories(docSnap.data().items);
      }
    });

    return () => unsub();
  }, []);

  // 🔥 Handle input change
  const handleChange = (index, field, value) => {
    const updated = [...categories];
    updated[index][field] = value;
    setCategories(updated);
  };

  // 🔥 Save categories
  const handleSave = async () => {
    await setDoc(doc(db, 'categories', 'main'), {
      items: categories
    });

    alert("Categories updated!");
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Category Manager</h2>

      {categories.map((cat, index) => (
        <div key={cat.id} style={{ marginBottom: "20px" }}>
          <h4>{cat.label}</h4>

          {/* ✅ Image Preview */}
          {cat.image && (
            <img src={cat.image} alt="" width="120" />
          )}

          <br /><br />

          {/* ✅ Image URL Input */}
          <input
            type="text"
            placeholder="Paste image URL"
            value={cat.image}
            onChange={(e) =>
              handleChange(index, 'image', e.target.value)
            }
            style={{ width: "300px" }}
          />
        </div>
      ))}

      <br />

      <button onClick={handleSave}>
        Save Categories
      </button>
    </div>
  );
}
